import base64, os, subprocess
os.chdir(r"C:\sistema-catalogos")

with open("auth.py", "wb") as f: f.write(base64.b64decode(""))
print("OK: auth.py")

with open("ml_buscador.py", "wb") as f: f.write(base64.b64decode(""))
print("OK: ml_buscador.py")


cmds = [
    ["git", "add", "auth.py", "ml_buscador.py"],
    ["git", "commit", "-m", "fix: auth simplificado + ML token Supabase"],
    ["git", "push"]
]
for cmd in cmds:
    r = subprocess.run(cmd, capture_output=True, text=True)
    print(' '.join(cmd[:2]), '->', r.stdout.strip() or r.stderr.strip())
print("PRONTO! Aguarde o Render fazer o deploy (~2min)")
